1	import { useMemo, useEffect, useRef } from "react";
2	import { useMarkets, useMarket, useEngineStats } from "@/lib/query/hooks";
3	import { formatProbability } from "@/lib/utils/format";
4	import { useForceGraph } from "./useForceGraph";
5	import { deriveEdgesFromCliques, mergeEdges } from "./deriveEdges";
6	import { select } from "d3-selection";
7	import { zoom as d3Zoom, zoomIdentity } from "d3-zoom";
8	import { drag as d3Drag } from "d3-drag";
9	import type { MarketSummary, CliqueSummary } from "@/lib/api/types";
10	
11	// ---------------------------------------------------------------------------
12	// Types
13	// ---------------------------------------------------------------------------
14	
15	interface GraphEdge {
16	  from: string;
17	  to: string;
18	  label?: string;
19	}
20	
21	interface ForceDirectedGraphProps {
22	  focusMarketId?: string;
23	  conditionalEdges?: GraphEdge[];
24	  onNodeClick?: (marketId: string) => void;
25	}
26	
27	// ---------------------------------------------------------------------------
28	// Constants
29	// ---------------------------------------------------------------------------
30	
31	const NODE_W = 160;
32	const NODE_H = 72;
33	const SVG_WIDTH = 600;
34	const SVG_HEIGHT = 400;
35	
36	// ---------------------------------------------------------------------------
37	// Sub-components
38	// ---------------------------------------------------------------------------
39	
40	function MarketNode({
41	  x,
42	  y,
43	  node,
44	  isFocus,
45	  isDimmed,
46	  detail,
47	  onClick,
48	}: {
49	  x: number;
50	  y: number;
51	  node: { id: string; title: string; status: string };
52	  isFocus: boolean;
53	  isDimmed: boolean;
54	  detail?: { marginals: Record<string, number>; outcomes: Array<{ id: string; name: string }> };
55	  onClick?: () => void;
56	}) {
57	  const borderColor = isFocus ? "var(--color-primary)" : "var(--color-border)";
58	  const bg = isFocus ? "var(--color-bg-surface)" : "var(--color-bg)";
59	  const truncatedTitle = node.title.length > 28 ? node.title.slice(0, 26) + "\u2026" : node.title;
60	
61	  return (
62	    <g
63	      transform={`translate(${x - NODE_W / 2}, ${y - NODE_H / 2})`}
64	      style={{ cursor: onClick ? "pointer" : "default", opacity: isDimmed ? 0.3 : 1 }}
65	      onClick={onClick ? (e) => { e.stopPropagation(); onClick(); } : undefined}
66	      data-node-id={node.id}
67	    >
68	      <rect
69	        width={NODE_W}
70	        height={NODE_H}
71	        rx={8}
72	        fill={bg}
73	        stroke={borderColor}
74	        strokeWidth={isFocus ? 2.5 : 1}
75	      />
76	      <text
77	        x={NODE_W / 2}
78	        y={18}
79	        textAnchor="middle"
80	        fontSize="11"
81	        fontWeight={600}
82	        fill="var(--color-text)"
83	      >
84	        {truncatedTitle}
85	      </text>
86	      {detail && detail.outcomes.length > 0 && (
87	        <g transform="translate(8, 28)">
88	          {detail.outcomes.slice(0, 3).map((o, i) => {
89	            const p = detail.marginals[o.id] ?? 0;
90	            const barW = NODE_W - 16;
91	            return (
92	              <g key={o.id} transform={`translate(0, ${i * 14})`}>
93	                <rect width={barW} height={10} rx={3} fill="var(--color-border)" opacity={0.3} />
94	                <rect
95	                  width={Math.max(2, barW * p)}
96	                  height={10}
97	                  rx={3}
98	                  fill={p > 0.5 ? "var(--color-success)" : "var(--color-info)"}
99	                  opacity={0.7}
100	                />
101	                <text x={4} y={8} fontSize="8" fill="var(--color-text)" fontWeight={500}>
102	                  {o.name}: {formatProbability(p)}
103	                </text>
104	              </g>
105	            );
106	          })}
107	        </g>
108	      )}
109	      {/* Status dot */}
110	      <circle
111	        cx={NODE_W - 10}
112	        cy={10}
113	        r={4}
114	        fill={
115	          node.status === "active"
116	            ? "var(--color-success)"
117	            : node.status === "resolved"
118	              ? "var(--color-info)"
119	              : "var(--color-text-muted)"
120	        }
121	      />
122	    </g>
123	  );
124	}
125	
126	function EdgeLine({
127	  x1,
128	  y1,
129	  x2,
130	  y2,
131	  isHighlighted,
132	}: {
133	  x1: number;
134	  y1: number;
135	  x2: number;
136	  y2: number;
137	  isHighlighted: boolean;
138	}) {
139	  return (
140	    <line
141	      x1={x1}
142	      y1={y1}
143	      x2={x2}
144	      y2={y2}
145	      stroke="var(--color-primary)"
146	      strokeWidth={isHighlighted ? 2 : 1.5}
147	      strokeDasharray={isHighlighted ? "none" : "6 3"}
148	      opacity={isHighlighted ? 0.8 : 0.4}
149	    />
150	  );
151	}
152	
153	function CliqueOverlay({
154	  clique,
155	  nodePositions,
156	}: {
157	  clique: CliqueSummary;
158	  nodePositions: Map<string, { x: number; y: number }>;
159	}) {
160	  const memberPositions = clique.nodes
161	    .map((id) => nodePositions.get(id))
162	    .filter((p): p is { x: number; y: number } => p != null);
163	
164	  if (memberPositions.length < 2) return null;
165	
166	  const pad = 20;
167	  const xs = memberPositions.map((p) => p.x);
168	  const ys = memberPositions.map((p) => p.y);
169	  const minX = Math.min(...xs) - NODE_W / 2 - pad;
170	  const minY = Math.min(...ys) - NODE_H / 2 - pad;
171	  const maxX = Math.max(...xs) + NODE_W / 2 + pad;
172	  const maxY = Math.max(...ys) + NODE_H / 2 + pad;
173	
174	  return (
175	    <g>
176	      <rect
177	        x={minX}
178	        y={minY}
179	        width={maxX - minX}
180	        height={maxY - minY}
181	        rx={12}
182	        fill="var(--color-primary)"
183	        fillOpacity={0.06}
184	        stroke="var(--color-primary)"
185	        strokeWidth={1}
186	        strokeDasharray="4 4"
187	        strokeOpacity={0.3}
188	      />
189	      <text x={minX + 6} y={minY + 14} fontSize="9" fill="var(--color-primary)" opacity={0.7}>
190	        Clique {clique.id}
191	      </text>
192	    </g>
193	  );
194	}
195	
196	function NodeWithDetail({
197	  x,
198	  y,
199	  node,
200	  isFocus,
201	  isDimmed,
202	  onClick,
203	}: {
204	  x: number;
205	  y: number;
206	  node: { id: string; title: string; status: string };
207	  isFocus: boolean;
208	  isDimmed: boolean;
209	  onClick?: () => void;
210	}) {
211	  const { data } = useMarket(node.id);
212	  const detail = data
213	    ? { marginals: data.market.marginals, outcomes: data.market.outcomes }
214	    : undefined;
215	  return (
216	    <MarketNode
217	      x={x}
218	      y={y}
219	      node={node}
220	      isFocus={isFocus}
221	      isDimmed={isDimmed}
222	      detail={detail}
223	      onClick={onClick}
224	    />
225	  );
226	}
227	
228	// ---------------------------------------------------------------------------
229	// Main component
230	// ---------------------------------------------------------------------------
231	
232	export function ForceDirectedGraph({
233	  focusMarketId,
234	  conditionalEdges = [],
235	  onNodeClick,
236	}: ForceDirectedGraphProps) {
237	  const { data: marketsData, isLoading } = useMarkets();
238	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
239	
240	  const markets = marketsData?.markets ?? [];
241	  const cliques = engineStats?.cliques.cliques ?? [];
242	
243	  // Derive force graph input nodes
244	  const forceInputNodes = useMemo(
245	    () => markets.map((m: MarketSummary) => ({ id: m.id, title: m.title, status: m.status })),
246	    [markets],
247	  );
248	
249	  // Derive edges from cliques + conditional edges
250	  const forceInputLinks = useMemo(() => {
251	    const cliqueEdges = deriveEdgesFromCliques(cliques);
252	    return mergeEdges(cliqueEdges, conditionalEdges);
253	  }, [cliques, conditionalEdges]);
254	
255	  const graphOptions = useMemo(() => ({ width: SVG_WIDTH, height: SVG_HEIGHT }), []);
256	  const { positions, getSimulation, getNodes, flushPositions } = useForceGraph(
257	    forceInputNodes,
258	    forceInputLinks,
259	    graphOptions,
260	  );
261	
262	  // Build position lookup
263	  const nodePositionMap = useMemo(() => {
264	    const map = new Map<string, { x: number; y: number }>();
265	    for (const np of positions.nodes) {
266	      map.set(np.id, { x: np.x, y: np.y });
