39	function layoutNodes(markets: MarketSummary[]): GraphNode[] {
40	  // Arrange in a circle for small N, grid for larger
41	  const n = markets.length;
42	  if (n === 0) return [];
43	
44	  const cx = 300;
45	  const cy = 200;
46	  const radius = Math.max(120, n * 40);
47	
48	  return markets.map((m, i) => {
49	    const angle = (2 * Math.PI * i) / n - Math.PI / 2;
50	    return {
51	      id: m.id,
52	      title: m.title.length > 28 ? m.title.slice(0, 26) + "…" : m.title,
53	      x: cx + radius * Math.cos(angle),
54	      y: cy + radius * Math.sin(angle),
55	      marginals: {},
56	      outcomeName: "",
57	      status: m.status,
58	    };
59	  });
60	}
