141	function EdgeLine({ from, to, nodes }: { from: string; to: string; nodes: GraphNode[] }) {
142	  const a = nodes.find((n) => n.id === from);
143	  const b = nodes.find((n) => n.id === to);
144	  if (!a || !b) return null;
145	
146	  // Arrow from a → b
147	  const dx = b.x - a.x;
148	  const dy = b.y - a.y;
149	  const dist = Math.sqrt(dx * dx + dy * dy);
150	  if (dist === 0) return null;
151	
152	  const ux = dx / dist;
153	  const uy = dy / dist;
154	
155	  // Start/end offset by node radius
156	  const startX = a.x + ux * (NODE_W / 2 + 4);
157	  const startY = a.y + uy * (NODE_H / 2 + 4);
158	  const endX = b.x - ux * (NODE_W / 2 + 8);
159	  const endY = b.y - uy * (NODE_H / 2 + 8);
160	
161	  return (
162	    <g>
163	      <line
164	        x1={startX}
165	        y1={startY}
166	        x2={endX}
167	        y2={endY}
168	        stroke="var(--color-primary)"
169	        strokeWidth={1.5}
170	        strokeDasharray="6 3"
171	        opacity={0.6}
172	      />
173	      {/* Arrowhead */}
174	      <polygon
175	        points={`${endX},${endY} ${endX - ux * 8 - uy * 4},${endY - uy * 8 + ux * 4} ${endX - ux * 8 + uy * 4},${endY - uy * 8 - ux * 4}`}
176	        fill="var(--color-primary)"
177	        opacity={0.6}
178	      />
179	    </g>
180	  );
181	}
