359	          No markets to visualize.
360	        </div>
361	      </div>
362	    );
363	  }
364	
365	  // Compute SVG viewBox from node positions
366	  const xs = nodes.map((n) => n.x);
367	  const ys = nodes.map((n) => n.y);
368	  const vbX = Math.min(...xs) - NODE_W / 2 - PADDING;
369	  const vbY = Math.min(...ys) - NODE_H / 2 - PADDING;
370	  const vbW = Math.max(...xs) - Math.min(...xs) + NODE_W + PADDING * 2;
371	  const vbH = Math.max(...ys) - Math.min(...ys) + NODE_H + PADDING * 2;
372	
373	  return (
374	    <div style={panelStyle}>
375	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
376	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
