39	  const handleCellClick = (entryIndex: number, outcomeId: string, currentP: number) => {
40	    if (!isConfigured) return;
41	    setEditing({ entryIndex, outcomeId, probability: currentP });
42	  };
43	
44	  const handleSubmit = () => {
45	    if (!editing || !cptData) return;
46	    const entry = entries[editing.entryIndex];
47	    if (!entry) return;
48	
49	    const currentP = entry.marginals[editing.outcomeId] ?? 0;
50	    draftEdits.stageDraft({
51	      entryIndex: editing.entryIndex,
52	      outcomeId: editing.outcomeId,
53	      probability: editing.probability,
54	      context: entry.context,
55	      previousProbability: currentP,
56	    });
57	    setEditing(null);
58	  };
59	
