176	                      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
177	                        <div style={{
178	                          width: 40,
179	                          height: 6,
180	                          borderRadius: 3,
181	                          background: "var(--color-border)",
182	                          overflow: "hidden",
183	                        }}>
184	                          <div style={{
185	                            width: `${Math.max(2, p * 100)}%`,
186	                            height: "100%",
187	                            borderRadius: 3,
188	                            background: isDrafted ? "var(--color-info)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)",
189	                          }} />
190	                        </div>
191	                        <span>{formatProbability(p)}{isDrafted ? " *" : ""}</span>
192	                      </div>
193	                    </td>
194	                  );
195	                })}
196	              </tr>
197	            ))}
198	          </tbody>
199	        </table>
200	      </div>
201	
202	      {draftEdits.hasDrafts && (
203	        <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center", marginTop: "var(--space-sm)" }}>
204	          <button onClick={handleCommitDrafts} disabled={mutation.isPending} style={setBtnStyle}>
205	            {mutation.isPending ? "Submitting…" : `Commit ${draftEdits.allDrafts().length} draft(s)`}
206	          </button>
