61	/**
62	 * Trigger a JSON file download in the browser.
63	 */
64	export function downloadJson(data: NetworkExportSchema, filename: string): void {
65	  const json = JSON.stringify(data, null, 2);
66	  const blob = new Blob([json], { type: "application/json" });
67	  const url = URL.createObjectURL(blob);
68	  const a = document.createElement("a");
69	  a.href = url;
70	  a.download = filename;
71	  a.click();
72	  URL.revokeObjectURL(url);
73	}
