1	import { useEffect } from "react";
2	import { useHistory } from "./HistoryContext";
3	
4	/**
5	 * Returns true if the active element is an input/textarea/select/contenteditable,
6	 * meaning native browser undo should be used instead.
7	 */
8	export function isEditableElement(el: Element | null): boolean {
9	  if (!el) return false;
10	  const tag = el.tagName;
11	  if (tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT") return true;
12	  if ((el as HTMLElement).isContentEditable || (el as HTMLElement).contentEditable === "true") return true;
13	  return false;
14	}
15	
16	/**
17	 * Listens for Ctrl+Z (undo) and Ctrl+Shift+Z / Ctrl+Y (redo) on the document.
18	 * Skips events when an editable element is focused.
19	 */
20	export function useUndoRedoKeyboard() {
21	  const { undo, redo, canUndo, canRedo } = useHistory();
22	
23	  useEffect(() => {
24	    function handleKeyDown(e: KeyboardEvent) {
25	      if (isEditableElement(document.activeElement)) return;
26	
27	      const isCtrl = e.ctrlKey || e.metaKey;
28	      if (!isCtrl) return;
29	
30	      if (e.key === "z" && !e.shiftKey) {
31	        if (canUndo) {
32	          e.preventDefault();
33	          undo();
34	        }
35	      } else if ((e.key === "z" && e.shiftKey) || e.key === "y") {
36	        if (canRedo) {
37	          e.preventDefault();
38	          redo();
39	        }
40	      }
41	    }
42	
43	    document.addEventListener("keydown", handleKeyDown);
44	    return () => document.removeEventListener("keydown", handleKeyDown);
45	  }, [undo, redo, canUndo, canRedo]);
46	}
