1	import { useCallback } from "react";
2	import { useAssumptions, type Assumption } from "@/features/assumptions/AssumptionContext";
3	import { useHistory } from "./HistoryContext";
4	import { AssumptionAddCommand, AssumptionRemoveCommand, AssumptionClearAllCommand } from "./commands";
5	
6	/**
7	 * Wraps useAssumptions() with history tracking.
8	 * Returns the same API surface but each mutation pushes a command onto the undo stack.
9	 */
10	export function useHistoryAssumptions() {
11	  const assumptions = useAssumptions();
12	  const history = useHistory();
13	
14	  const addAssumption = useCallback(
15	    (a: Assumption) => {
16	      const previous = assumptions.getAssumption(a.variableId);
17	      const cmd = new AssumptionAddCommand({
18	        assumption: a,
19	        previousAssumption: previous,
20	        addAssumption: assumptions.addAssumption,
21	        removeAssumption: assumptions.removeAssumption,
22	      });
23	      cmd.execute();
24	      history.push(cmd);
25	    },
26	    [assumptions, history],
27	  );
28	
29	  const removeAssumption = useCallback(
30	    (variableId: string) => {
31	      const existing = assumptions.getAssumption(variableId);
32	      if (!existing) return;
33	      const cmd = new AssumptionRemoveCommand({
34	        removedAssumption: existing,
35	        addAssumption: assumptions.addAssumption,
36	        removeAssumption: assumptions.removeAssumption,
37	      });
38	      cmd.execute();
39	      history.push(cmd);
40	    },
41	    [assumptions, history],
42	  );
43	
44	  const clearAll = useCallback(() => {
45	    if (assumptions.assumptions.length === 0) return;
46	    const cmd = new AssumptionClearAllCommand({
47	      previousAssumptions: assumptions.assumptions,
48	      setAllAssumptions: assumptions.setAllAssumptions,
49	      clearAll: assumptions.clearAll,
50	    });
51	    cmd.execute();
52	    history.push(cmd);
53	  }, [assumptions, history]);
54	
55	  return {
56	    ...assumptions,
57	    addAssumption,
58	    removeAssumption,
59	    clearAll,
60	  };
61	}
