53	  isDimmed: boolean;
54	  detail?: { marginals: Record<string, number>; outcomes: Array<{ id: string; name: string }> };
55	  onClick?: () => void;
56	}) {
57	  const borderColor = isFocus ? "var(--color-primary)" : "var(--color-border)";
