93	                <rect width={barW} height={10} rx={3} fill="var(--color-border)" opacity={0.3} />
94	                <rect
95	                  width={Math.max(2, barW * p)}
96	                  height={10}
97	                  rx={3}
98	                  fill={p > 0.5 ? "var(--color-success)" : "var(--color-info)"}
99	                  opacity={0.7}
100	                />
101	                <text x={4} y={8} fontSize="8" fill="var(--color-text)" fontWeight={500}>
102	                  {o.name}: {formatProbability(p)}
103	                </text>
