62	function MarketNode({
63	  node,
64	  isFocus,
65	  detail,
66	  animationClass,
67	}: {
68	  node: GraphNode;
69	  isFocus: boolean;
70	  detail?: { marginals: Record<string, number>; outcomes: Array<{ id: string; name: string }> };
71	  animationClass?: string;
72	}) {
73	  const borderColor = isFocus ? "var(--color-primary)" : "var(--color-border)";
74	  const bg = isFocus ? "var(--color-bg-surface)" : "var(--color-bg)";
75	
76	  return (
77	    <g
78	      transform={`translate(${node.x - NODE_W / 2}, ${node.y - NODE_H / 2})`}
79	      className={animationClass}
80	    >
81	      <rect
82	        width={NODE_W}
83	        height={NODE_H}
84	        rx={8}
85	        fill={bg}
86	        stroke={borderColor}
87	        strokeWidth={isFocus ? 2.5 : 1}
88	      />
89	      <text
90	        x={NODE_W / 2}
91	        y={18}
92	        textAnchor="middle"
93	        fontSize="11"
94	        fontWeight={600}
95	        fill="var(--color-text)"
96	      >
97	        {node.title}
98	      </text>
99	      {/* Mini probability bars */}
100	      {detail && detail.outcomes.length > 0 && (
101	        <g transform="translate(8, 28)">
102	          {detail.outcomes.slice(0, 3).map((o, i) => {
103	            const p = detail.marginals[o.id] ?? 0;
104	            const barW = NODE_W - 16;
105	            return (
106	              <g key={o.id} transform={`translate(0, ${i * 14})`}>
107	                <rect width={barW} height={10} rx={3} fill="var(--color-border)" opacity={0.3} />
108	                <rect
109	                  width={Math.max(2, barW * p)}
