224	/** Renders a mini detail-fetcher node that uses useMarket */
225	function NodeWithDetail({
226	  node,
227	  isFocus,
228	  animationClass,
229	}: {
230	  node: GraphNode;
231	  isFocus: boolean;
232	  animationClass?: string;
233	}) {
234	  const { data } = useMarket(node.id);
235	  const detail = data
