378	        </h3>
379	
380	        <div style={{ display: "flex", alignItems: "center", gap: "var(--space-sm)" }}>
381	          {/* Export / Import buttons */}
382	          <div style={{ display: "flex", gap: 4 }}>
383	            <button
384	              type="button"
385	              onClick={handleExport}
386	              style={smallButtonStyle}
387	              title="Export network as JSON"
