408	            )}
409	            <input
410	              ref={fileInputRef}
411	              type="file"
412	              accept=".json"
413	              style={{ display: "none" }}
414	              onChange={handleImportFile}
415	            />
416	          </div>
417	
418	          <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
419	            {markets.length} variable{markets.length !== 1 ? "s" : ""}
420	            {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
421	            {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
422	            {engineStats && !snapshot && ` · JT width ${engineStats.cliques.junction_tree_width}`}
423	          </div>
424	        </div>
425	      </div>
426	
427	      {importError && (
428	        <div style={{ fontSize: "0.75rem", color: "var(--color-danger)", marginBottom: "var(--space-sm)" }}>
429	          Import failed: {importError}
430	        </div>
431	      )}
432	
433	      <svg
434	        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
435	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
436	      >
437	        <defs>
438	          {/* Glow filter for evidence node */}
439	          <filter id="evidence-glow" x="-30%" y="-30%" width="160%" height="160%">
440	            <feGaussianBlur in="SourceAlpha" stdDeviation="6" result="blur" />
441	            <feFlood floodColor="var(--color-primary)" floodOpacity="0.6" result="color" />
442	            <feComposite in="color" in2="blur" operator="in" result="glow" />
443	            <feMerge>
444	              <feMergeNode in="glow" />
445	              <feMergeNode in="SourceGraphic" />
446	            </feMerge>
447	          </filter>
448	          {/* Highlight filter for nodes reached by propagation wave */}
449	          <filter id="propagation-highlight" x="-15%" y="-15%" width="130%" height="130%">
450	            <feDropShadow dx="0" dy="0" stdDeviation="4" floodColor="var(--color-info)" floodOpacity="0.5" />
451	          </filter>
452	        </defs>
453	        <style>{`
454	          @keyframes evidence-pulse {
455	            0% { opacity: 0.7; }
456	            50% { opacity: 1; }
457	            100% { opacity: 0.7; }
458	          }
459	          @keyframes propagation-arrive {
460	            0% { opacity: 0; transform: scale(0.95); }
461	            50% { opacity: 1; transform: scale(1.02); }
462	            100% { opacity: 1; transform: scale(1); }
463	          }
464	          @keyframes edge-flow {
465	            0% { stroke-dashoffset: 16; }
466	            100% { stroke-dashoffset: 0; }
467	          }
