481	        ))}
482	
483	        {/* Animated propagation edges */}
484	        {animatingEdges.size > 0 && allEdges.map((e) => {
485	          const ek = e.source < e.target ? `${e.source}::${e.target}` : `${e.target}::${e.source}`;
486	          if (!animatingEdges.has(ek)) return null;
487	          const a = nodes.find((n) => n.id === e.source);
488	          const b = nodes.find((n) => n.id === e.target);
489	          if (!a || !b) return null;
490	          const dx = b.x - a.x;
491	          const dy = b.y - a.y;
492	          const dist = Math.sqrt(dx * dx + dy * dy);
493	          if (dist === 0) return null;
494	          const ux = dx / dist;
495	          const uy = dy / dist;
496	          const sx = a.x + ux * (NODE_W / 2 + 4);
497	          const sy = a.y + uy * (NODE_H / 2 + 4);
498	          const ex = b.x - ux * (NODE_W / 2 + 8);
499	          const ey = b.y - uy * (NODE_H / 2 + 8);
500	          return (
501	            <line
502	              key={`anim-${ek}`}
503	              x1={sx} y1={sy} x2={ex} y2={ey}
