505	              strokeWidth={2.5}
506	              strokeDasharray="8 8"
507	              opacity={0.8}
508	              className="propagation-edge"
509	            />
510	          );
511	        })}
512	
513	        {/* Market nodes */}
514	        {nodes.map((node) => {
