560	const panelStyle: React.CSSProperties = {
561	  padding: "var(--space-md)",
562	  borderRadius: "var(--radius-md)",
563	  border: "1px solid var(--color-border)",
564	  background: "var(--color-bg-surface)",
565	};
566	
567	const smallButtonStyle: React.CSSProperties = {
568	  padding: "2px 8px",
