import { useRef, useCallback, useState } from "react";
import { buildNetworkExport, downloadJson } from "./networkExport";
import { readAndValidateFile } from "./networkImport";
import type { NetworkExportSchema } from "./networkExportSchema";
import type { MarketSummary, CliqueSummary } from "@/lib/api/types";
import type { GraphEdge } from "./deriveEdges";

export type GraphView = "force" | "circular";

interface GraphToolbarProps {
  /** Current graph view mode */
  view: GraphView;
  /** Callback when view is toggled */
  onViewChange: (view: GraphView) => void;
  /** Markets data for export */
  markets: MarketSummary[];
  /** Node positions for export */
  nodePositions: Array<{ id: string; x: number; y: number }>;
  /** Clique edges for export */
  cliqueEdges: GraphEdge[];
  /** Conditional edges for export */
  conditionalEdges: Array<{ from: string; to: string }>;
  /** Cliques data for export */
  cliques: CliqueSummary[];
  /** Called with imported data on success */
  onImport: (data: NetworkExportSchema) => void;
  /** Currently viewing a snapshot? */
  hasSnapshot: boolean;
  /** Clear the current snapshot */
  onClearSnapshot: () => void;
}

export function GraphToolbar({
  view,
  onViewChange,
  markets,
  nodePositions,
  cliqueEdges,
  conditionalEdges,
  cliques,
  onImport,
  hasSnapshot,
  onClearSnapshot,
}: GraphToolbarProps) {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [importError, setImportError] = useState<string | null>(null);

  const handleExport = useCallback(() => {
    const data = buildNetworkExport(markets, nodePositions, cliqueEdges, conditionalEdges, cliques);
    const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
    downloadJson(data, `bayes-network-${ts}.json`);
  }, [markets, nodePositions, cliqueEdges, conditionalEdges, cliques]);

  const handleImportFile = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportError(null);
    const result = await readAndValidateFile(file);
    if (result.ok) {
      onImport(result.data);
    } else {
      setImportError(result.error);
    }
    e.target.value = "";
  }, [onImport]);

  return (
    <div style={toolbarStyle}>
      <div style={{ display: "flex", alignItems: "center", gap: "var(--space-sm)" }}>
        {/* View toggle */}
        <div style={toggleGroupStyle}>
          <button
            type="button"
            onClick={() => onViewChange("force")}
            style={view === "force" ? toggleActiveStyle : toggleStyle}
          >
            Force
          </button>
          <button
            type="button"
            onClick={() => onViewChange("circular")}
            style={view === "circular" ? toggleActiveStyle : toggleStyle}
          >
            Circular
          </button>
        </div>

        {/* Export / Import buttons */}
        <button type="button" onClick={handleExport} style={btnStyle} title="Export network as JSON">
          Export
        </button>
        <button
          type="button"
          onClick={() => fileInputRef.current?.click()}
          style={btnStyle}
          title="Import network from JSON"
        >
          Import
        </button>
        {hasSnapshot && (
          <button
            type="button"
            onClick={() => { onClearSnapshot(); setImportError(null); }}
            style={{ ...btnStyle, color: "var(--color-danger)" }}
            title="Return to live network"
          >
            Clear
          </button>
        )}
        <input
          ref={fileInputRef}
          type="file"
          accept=".json"
          style={{ display: "none" }}
          onChange={handleImportFile}
        />
      </div>

      {importError && (
        <div style={{ fontSize: "0.75rem", color: "var(--color-danger)", marginTop: 4 }}>
          Import failed: {importError}
        </div>
      )}
    </div>
  );
}

const toolbarStyle: React.CSSProperties = {
  display: "flex",
  flexDirection: "column",
  padding: "var(--space-sm) var(--space-md)",
  borderRadius: "var(--radius-md)",
  border: "1px solid var(--color-border)",
  background: "var(--color-bg-surface)",
};

const toggleGroupStyle: React.CSSProperties = {
  display: "flex",
  borderRadius: "var(--radius-sm)",
  border: "1px solid var(--color-border)",
  overflow: "hidden",
};

const toggleStyle: React.CSSProperties = {
  padding: "2px 10px",
  fontSize: "0.7rem",
  border: "none",
  background: "var(--color-bg)",
  color: "var(--color-text-muted)",
  cursor: "pointer",
  fontWeight: 500,
};

const toggleActiveStyle: React.CSSProperties = {
  ...toggleStyle,
  background: "var(--color-primary)",
  color: "#fff",
  fontWeight: 600,
};

const btnStyle: React.CSSProperties = {
  padding: "2px 8px",
  fontSize: "0.7rem",
  borderRadius: "var(--radius-sm)",
  border: "1px solid var(--color-border)",
  background: "var(--color-bg)",
  color: "var(--color-text)",
  cursor: "pointer",
  fontWeight: 500,
};

