        </div>
        <div>
          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Utilization</div>
          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600, color: utilColor }}>
            {(marketRisk.utilization * 100).toFixed(1)}%
