      {expanded && (
        <tr>
          <td colSpan={4} style={{ padding: "0 12px 8px 12px" }}>
            <pre style={payloadStyle}>{JSON.stringify(event.payload, null, 2)}</pre>
          </td>
        </tr>
      )}
    </>
  );
}

