function defaultQueryState<T>(data?: T) {
  return {
    data,
    isLoading: false,
    error: null,
    isFetching: false,
    isError: false,
    isSuccess: data !== undefined,
    isPending: false,
    status: (data !== undefined ? "success" : "pending") as "success" | "pending" | "error",
    refetch: vi.fn(),
    fetchStatus: "idle" as const,
    failureCount: 0,
    failureReason: null,
    dataUpdatedAt: 0,
    errorUpdatedAt: 0,
    isLoadingError: false,
    isFetched: true,
