// ---------------------------------------------------------------------------

function defaultQueryState<T>(data?: T) {
  return {
    data,
    isLoading: false,
    error: null,
    isFetching: false,
    isError: false,
    isSuccess: data !== undefined,
    isPending: false,
    status: (data !== undefined ? "success" : "pending") as "success" | "pending" | "error",
    refetch: vi.fn(),
    fetchStatus: "idle" as const,
    failureCount: 0,
    failureReason: null,
    dataUpdatedAt: 0,
    errorUpdatedAt: 0,
    isLoadingError: false,
    isFetched: true,
    isFetchedAfterMount: true,
    isInitialLoading: false,
    isPlaceholderData: false,
    isPaused: false,
    isRefetchError: false,
    isRefetching: false,
    isStale: false,
    errorUpdateCount: 0,
    promise: Promise.resolve(data as T),
  } as unknown as ReturnType<typeof useMarket>;
}

function defaultMutationState() {
  return {
    mutate: vi.fn(),
    mutateAsync: vi.fn(),
    reset: vi.fn(),
    isPending: false,
    isSuccess: false,
    isError: false,
    isIdle: true,
    status: "idle" as const,
    data: undefined,
    error: null,
    variables: undefined,
    failureCount: 0,
    failureReason: null,
    submittedAt: 0,
    context: undefined,
  } as unknown as ReturnType<typeof useResolveMarket>;
}

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const mockMarket = {
  market: {
    id: "m1",
    title: "ETH Price > $3000",
    description: "Will ETH trade above $3000?",
    variableId: "eth_price",
    status: "active" as const,
    outcomes: [
      { id: "yes", name: "Yes" },
      { id: "no", name: "No" },
